# grafana_dashboard.json (excerpt — paste into Grafana JSON model)
# Uses a PostgreSQL datasource named "finops-db".
# Shows MTD spend, daily trend, and team breakdown for the executive view.

{
  "title": "Claude FinOps Executive View",
  "refresh": "5m",
  "panels": [
    {
      "type": "stat",
      "title": "MTD Spend",
      "gridPos": {"x": 0, "y": 0, "w": 4, "h": 4},
      "targets": [{
        "rawSql": "SELECT SUM(cost_usd) FROM usage_events WHERE DATE_TRUNC('month', ts) = DATE_TRUNC('month', NOW())",
        "format": "table"
      }],
      "options": {"unit": "currencyUSD", "colorMode": "background"}
    },
    {
      "type": "stat",
      "title": "Cache Hit Rate",
      "gridPos": {"x": 4, "y": 0, "w": 4, "h": 4},
      "targets": [{
        "rawSql": "SELECT SUM(cache_read_input_tokens)::FLOAT / NULLIF(SUM(input_tokens), 0) FROM usage_events WHERE DATE_TRUNC('month', ts) = DATE_TRUNC('month', NOW())",
        "format": "table"
      }],
      "options": {"unit": "percentunit", "thresholds": {"steps": [{"value": 0, "color": "red"}, {"value": 0.6, "color": "yellow"}, {"value": 0.75, "color": "green"}]}}
    },
    {
      "type": "timeseries",
      "title": "Daily Spend Trend",
      "gridPos": {"x": 0, "y": 4, "w": 12, "h": 8},
      "targets": [{
        "rawSql": "SELECT DATE(ts) AS time, SUM(cost_usd) FROM usage_events WHERE ts >= DATE_TRUNC('month', NOW()) GROUP BY DATE(ts) ORDER BY time",
        "format": "time_series"
      }]
    },
    {
      "type": "bargauge",
      "title": "Spend by Team",
      "gridPos": {"x": 12, "y": 0, "w": 12, "h": 8},
      "targets": [{
        "rawSql": "SELECT team_id, SUM(cost_usd) AS spend FROM usage_events WHERE DATE_TRUNC('month', ts) = DATE_TRUNC('month', NOW()) GROUP BY team_id ORDER BY spend DESC LIMIT 10",
        "format": "table"
      }]
    }
  ]
}
